const DOMAIN3_QUESTIONS = [
  { domain: 3, task: "3.1", q: "A team wants to script repeatable AWS changes from a terminal as part of deployment work. Which option would best help the team?", opts: ["AWS Management Console", "AWS CLI", "AWS Trusted Advisor", "Amazon Inspector"], ans: 1, explain: "The AWS CLI (Command Line Interface) allows users to manage AWS services from the command line and automation scripts." },
  { domain: 3, task: "3.1", q: "A company wants to define its AWS infrastructure in JSON or YAML files so the same environment can be deployed repeatedly. Which option best addresses this requirement?", opts: ["AWS Elastic Beanstalk", "AWS CloudFormation", "AWS Systems Manager Automation", "Amazon Lightsail"], ans: 1, explain: "AWS CloudFormation uses templates written in JSON or YAML to define and provision AWS infrastructure resources." },
  { domain: 3, task: "3.1", q: "A team wants dev, test, and production environments to be created from the same reviewed infrastructure definitions. What does AWS CloudFormation help the team do?", opts: ["Monitor application performance", "Define and provision infrastructure from templates", "Manage DNS records", "Create machine learning models"], ans: 1, explain: "AWS CloudFormation lets you define and provision infrastructure using template files, making deployments repeatable and consistent." },
  { domain: 3, task: "3.1", q: "A company wants to deploy a web application quickly without managing the underlying infrastructure. Which option best addresses this requirement?", opts: ["Amazon EC2", "AWS Lambda", "AWS Elastic Beanstalk", "Amazon ECS"], ans: 2, explain: "AWS Elastic Beanstalk automatically handles deployment, capacity provisioning, load balancing, and scaling for web applications." },
  { domain: 3, task: "3.1", q: "A company wants to run its application entirely on AWS without maintaining any on-premises infrastructure. Which choice best matches this operating model?", opts: ["Hybrid deployment", "On-premises deployment", "Cloud deployment", "Edge deployment"], ans: 2, explain: "A cloud deployment model runs the application entirely in the AWS cloud, with no on-premises infrastructure in the path." },
  { domain: 3, task: "3.1", q: "A company runs some workloads on-premises and some in AWS. What deployment model is this?", opts: ["Cloud-native", "Hybrid deployment", "Multi-cloud", "On-premises"], ans: 1, explain: "A hybrid deployment connects on-premises infrastructure with cloud-based resources, allowing workloads to run in both environments." },
  { domain: 3, task: "3.1", q: "A team wants to keep infrastructure changes reviewable and reusable across releases. Which benefits of CloudFormation help with that goal? (Choose TWO)", opts: ["It provides a GUI for resource management", "It supports infrastructure version control", "It automatically writes application code", "It enables repeatable infrastructure deployments", "It provides real-time monitoring"], ans: [1, 3], multi: true, explain: "CloudFormation templates can be stored in version control and used repeatedly to create identical infrastructure stacks." },
  { domain: 3, task: "3.1", q: "A company wants its infrastructure to be defined in templates, reviewed like code, and deployed repeatedly across environments. Which AWS service best supports this approach?", opts: ["AWS SAM", "AWS CloudFormation", "AWS Systems Manager", "Amazon Lightsail"], ans: 1, explain: "AWS CloudFormation supports repeatable infrastructure definitions using templates." },
  { domain: 3, task: "3.1", q: "A startup wants a managed way to deploy a web application while AWS handles scaling and load balancing. Which option is the best fit for this situation?", opts: ["Amazon EC2 with manual configuration", "AWS Elastic Beanstalk", "AWS Lambda", "Amazon Lightsail"], ans: 1, explain: "Elastic Beanstalk supports web applications and automatically manages scaling, load balancing, and health monitoring." },
  { domain: 3, task: "3.1", q: "A company wants infrastructure changes to be reviewed before deployment and tracked over time. Which approach supports this best?", opts: ["Using the AWS Management Console exclusively", "Defining infrastructure as code in version-controlled repositories", "Using AWS Trusted Advisor", "Manually documenting all changes"], ans: 1, explain: "Infrastructure as Code stored in version control enables code reviews, change tracking, and approval workflows for infrastructure changes." },
  { domain: 3, task: "3.1", q: "A team wants to define infrastructure once in templates and deploy the same stack repeatedly. Which option best addresses this requirement?", opts: ["AWS CloudFormation", "AWS SAM (Serverless Application Model)", "AWS Elastic Beanstalk", "Amazon Lightsail"], ans: 0, explain: "AWS CloudFormation lets you define infrastructure in JSON or YAML templates and deploy it repeatably." },
  { domain: 3, task: "3.1", q: "A company wants to standardize infrastructure deployments across environments. Which choice best matches these requirements?", opts: ["Use AWS CloudFormation templates", "Create resources manually in each account", "Rely on screenshots of console settings", "Use Amazon CloudWatch dashboards"], ans: 0, explain: "AWS CloudFormation templates help standardize infrastructure deployments across environments by using repeatable definitions." },
  { domain: 3, task: "3.1", q: "A team needs AWS to handle scaling, load balancing, and environment management for both a Java application and a Dockerized workload. Which service is designed for this use case?", opts: ["Amazon EC2 with manual setup", "AWS Elastic Beanstalk", "Amazon Lightsail", "AWS CloudTrail"], ans: 1, explain: "AWS Elastic Beanstalk supports common application platforms such as Java and Docker while managing the underlying environment for the customer." },
  { domain: 3, task: "3.1", q: "A company wants to extend its on-premises VMware environment to AWS. Which deployment model does this represent?", opts: ["Cloud-native deployment", "On-premises deployment", "Hybrid deployment", "Serverless deployment"], ans: 2, explain: "Extending on-premises VMware to AWS creates a hybrid deployment that spans both environments." },
  { domain: 3, task: "3.2", q: "A company needs to serve static content to users worldwide with low latency. Which option best addresses this requirement?", opts: ["Amazon S3 alone", "Amazon CloudFront", "AWS Direct Connect", "Amazon Route 53"], ans: 1, explain: "Amazon CloudFront is a CDN that caches content at edge locations worldwide, reducing latency for global users." },
  { domain: 3, task: "3.3", q: "A company runs batch processing jobs that require high-performance CPUs. Which EC2 instance type should they choose?", opts: ["General purpose", "Compute optimized", "Memory optimized", "Storage optimized"], ans: 1, explain: "Compute optimized instances (C family) are ideal for workloads requiring high-performance processors, like batch processing." },
  { domain: 3, task: "3.3", q: "A company needs to run machine learning training jobs that require GPU instances. Which EC2 instance type should they use?", opts: ["General purpose", "Compute optimized", "Accelerated computing", "Storage optimized"], ans: 2, explain: "Accelerated computing instances (P and G families) provide GPU capabilities for machine learning, graphics processing, and other GPU-intensive workloads." },
  { domain: 3, task: "3.3", q: "A startup wants to run a web application with unpredictable traffic. Which compute approach is MOST cost-effective?", opts: ["EC2 Reserved Instances", "AWS Lambda with API Gateway", "EC2 On-Demand Instances with fixed count", "Amazon Lightsail"], ans: 1, explain: "Lambda is most cost-effective for unpredictable traffic since you only pay for actual compute time used, with automatic scaling." },
  { domain: 3, task: "3.3", q: "A company runs Docker containers and wants AWS to manage the servers. Which launch type should they use with ECS?", opts: ["EC2 launch type", "Fargate launch type", "Lambda launch type", "Lightsail launch type"], ans: 1, explain: "The Fargate launch type with ECS runs containers without managing the underlying EC2 instances." },
  { domain: 3, task: "3.3", q: "A company needs to run thousands of short-lived batch jobs with varying resource requirements. Which service handles this?", opts: ["Amazon EC2 with manual management", "AWS Batch", "AWS Lambda", "Amazon ECS"], ans: 1, explain: "AWS Batch automatically provisions optimal compute resources and manages job queues for batch computing workloads." },
  { domain: 3, task: "3.3", q: "A company is migrating a legacy application that requires a specific OS kernel version. Which option is the best fit for this situation?", opts: ["AWS Lambda", "Amazon EC2", "AWS Fargate", "Amazon Lightsail"], ans: 1, explain: "EC2 provides full control over the operating system, allowing you to use specific kernel versions for legacy applications." },
  { domain: 3, task: "3.3", q: "A company wants to run containers and already has Kubernetes expertise. Which option best matches the team's existing operating model?", opts: ["Amazon ECS", "Amazon EKS", "AWS Lambda", "Amazon Lightsail"], ans: 1, explain: "Amazon EKS is the managed Kubernetes service, ideal for teams with existing Kubernetes expertise." },
  { domain: 3, task: "3.3", q: "A company needs to process millions of requests per second with static IP addresses. Which ELB type should they use?", opts: ["Application Load Balancer", "Network Load Balancer", "Classic Load Balancer", "Gateway Load Balancer"], ans: 1, explain: "NLB handles millions of requests per second with ultra-low latency and supports static/Elastic IP addresses." },
  { domain: 3, task: "3.3", q: "A company runs a stateless web application. Which combination provides high availability and automatic scaling?", opts: ["Single EC2 instance with EBS", "Auto Scaling group with ALB across multiple AZs", "Lambda with S3", "Lightsail with manual failover"], ans: 1, explain: "An Auto Scaling group with ALB across multiple AZs provides both automatic scaling and high availability for stateless web applications." },
  { domain: 3, task: "3.4", q: "A company needs a data warehouse for complex analytical queries across petabytes of data. Which option best addresses this requirement?", opts: ["Amazon RDS", "Amazon DynamoDB", "Amazon Redshift", "Amazon ElastiCache"], ans: 2, explain: "Amazon Redshift is a fully managed data warehouse designed for fast analytics across petabytes of structured data." },
  { domain: 3, task: "3.4", q: "A company needs a MongoDB-compatible document database. Which option best addresses this requirement?", opts: ["Amazon DynamoDB", "Amazon DocumentDB", "Amazon Neptune", "Amazon RDS"], ans: 1, explain: "Amazon DocumentDB is a MongoDB-compatible document database service designed for JSON data workloads." },
  { domain: 3, task: "3.4", q: "A company wants to use a database but only pay for actual usage with no upfront provisioning. Which option is best?", opts: ["RDS with Reserved Instances", "DynamoDB On-Demand mode", "Aurora Provisioned", "ElastiCache Reserved Nodes"], ans: 1, explain: "DynamoDB On-Demand mode charges per request with no capacity planning or upfront commitment required." },
  { domain: 3, task: "3.4", q: "A company needs a database for a recommendation engine that maps relationships between products, users, and purchases. Which service is ideal?", opts: ["Amazon DynamoDB", "Amazon Neptune", "Amazon RDS", "Amazon Redshift"], ans: 1, explain: "Neptune is a graph database ideal for recommendation engines that need to traverse relationships between entities." },
  { domain: 3, task: "3.5", q: "A company needs encrypted connectivity between their data center and AWS over the public internet. What should they use?", opts: ["AWS Direct Connect", "AWS Site-to-Site VPN", "VPC Peering", "Internet Gateway"], ans: 1, explain: "AWS Site-to-Site VPN creates an encrypted IPsec tunnel between the on-premises network and AWS over the public internet." },
  { domain: 3, task: "3.5", q: "A company needs to connect their AWS VPC to their on-premises network with consistent latency. Which TWO options provide this? (Choose TWO)", opts: ["AWS Direct Connect", "AWS Site-to-Site VPN over the internet", "AWS Direct Connect with VPN backup", "VPC Peering", "Internet Gateway"], ans: [0, 2], multi: true, explain: "Direct Connect provides consistent latency through dedicated connections. Direct Connect with VPN backup adds encryption and redundancy." },
  { domain: 3, task: "3.5", q: "A company needs DNS health checks to route traffic away from unhealthy endpoints. Which service provides this?", opts: ["Amazon CloudFront", "Amazon Route 53", "Elastic Load Balancing", "AWS WAF"], ans: 1, explain: "Route 53 health checks monitor endpoint health and can automatically route traffic away from unhealthy endpoints." },
  { domain: 3, task: "3.6", q: "A company needs a Windows-compatible file system in AWS. Which option best addresses this requirement?", opts: ["Amazon EFS", "Amazon FSx for Windows File Server", "Amazon S3", "Amazon EBS"], ans: 1, explain: "Amazon FSx for Windows File Server provides a fully managed Windows file system with SMB protocol support." },
  { domain: 3, task: "3.6", q: "A company wants to store critical records in a service designed to keep objects highly durable across multiple facilities in a Region. Which Amazon S3 characteristic addresses this concern?", opts: ["Low-latency block storage", "99.999999999% (11 nines) durability", "Single-server replication", "Automatic file locking on Windows shares"], ans: 1, explain: "Amazon S3 is designed for 11 nines of durability, making object loss extremely unlikely." },
  { domain: 3, task: "3.6", q: "A company needs to share files between multiple EC2 instances across AZs. Which storage service is best?", opts: ["Amazon EBS", "Amazon EFS", "Instance Store", "Amazon S3"], ans: 1, explain: "Amazon EFS can be mounted by multiple EC2 instances simultaneously across multiple Availability Zones." },
  { domain: 3, task: "3.6", q: "A company needs a fully managed Windows-native shared file system that supports SMB access and integration with Microsoft Active Directory. Which option best matches those file access needs?", opts: ["Amazon EFS", "Amazon FSx for Windows File Server", "Amazon S3", "Amazon EBS"], ans: 1, explain: "Amazon FSx for Windows File Server provides fully managed shared Windows file storage with native SMB support and Active Directory integration." },
  { domain: 3, task: "3.6", q: "A company wants to transition objects from S3 Standard to Glacier after 90 days automatically. What should they use?", opts: ["S3 Intelligent-Tiering", "S3 Lifecycle Policy", "S3 Replication", "S3 Transfer Acceleration"], ans: 1, explain: "S3 Lifecycle Policies can automatically transition objects to different storage classes (like Glacier) after a specified number of days." },
  { domain: 3, task: "3.6", q: "A company needs to store 100 TB of data that will be accessed once or twice a year for auditing. Which storage class is most cost-effective?", opts: ["S3 Standard", "S3 Standard-IA", "S3 Glacier", "S3 Glacier Deep Archive"], ans: 3, explain: "Glacier Deep Archive is the most cost-effective for data accessed very rarely (once or twice a year) and stored long-term." },
  { domain: 3, task: "3.6", q: "A company wants to protect against accidental deletion of S3 objects. Which TWO features help? (Choose TWO)", opts: ["S3 Versioning", "S3 MFA Delete", "S3 Transfer Acceleration", "S3 Intelligent-Tiering", "S3 Lifecycle Policies"], ans: [0, 1], multi: true, explain: "S3 Versioning preserves previous versions of objects, and MFA Delete requires MFA authentication to permanently delete versioned objects." },
  { domain: 3, task: "3.7", q: "A company needs to analyze customer reviews to determine sentiment (positive/negative). Which option best addresses that text-analysis requirement?", opts: ["Amazon Lex", "Amazon Comprehend", "Amazon Polly", "Amazon Textract"], ans: 1, explain: "Amazon Comprehend provides sentiment analysis as one of its NLP capabilities, determining if text is positive, negative, neutral, or mixed." },
  { domain: 3, task: "3.7", q: "A company needs to process millions of invoice images to extract line items and totals. Which service is best?", opts: ["Amazon Rekognition", "Amazon Textract", "Amazon Comprehend", "Amazon Translate"], ans: 1, explain: "Textract specializes in extracting text, forms, and tables from documents including invoices." },
  { domain: 3, task: "3.7", q: "A company wants to build a voice-controlled assistant for their mobile app. Which services should they use? (Choose TWO)", opts: ["Amazon Lex", "Amazon Polly", "Amazon Rekognition", "Amazon Textract", "Amazon Translate"], ans: [0, 1], multi: true, explain: "Lex provides speech recognition and conversational AI, while Polly converts response text to speech for the voice assistant." },
  { domain: 3, task: "3.7", q: "A company needs to detect faces in images for an identity verification system. Which option best addresses that computer vision need?", opts: ["Amazon Comprehend", "Amazon Rekognition", "Amazon Textract", "Amazon Forecast"], ans: 1, explain: "Amazon Rekognition provides facial detection, analysis, and comparison capabilities for identity verification." },
  { domain: 3, task: "3.7", q: "A company wants to analyze click-stream data from their website in real time. Which option best matches that streaming requirement?", opts: ["Amazon Athena", "Amazon Kinesis", "AWS Glue", "Amazon EMR"], ans: 1, explain: "Amazon Kinesis is designed for real-time streaming data ingestion and analysis, ideal for click-stream data." },
  { domain: 3, task: "3.8", q: "A team wants metrics, logs, and alarms in one place so they can watch resource health and react quickly when thresholds are crossed. Which option best addresses that monitoring requirement?", opts: ["Amazon CloudWatch", "AWS CloudTrail", "AWS Config", "Amazon EventBridge"], ans: 0, explain: "Amazon CloudWatch provides metrics, logs, and alarms for AWS resources and applications." },
  { domain: 3, task: "3.8", q: "A platform team needs a visual workflow to coordinate several AWS services into a business process. Which option best fits that orchestration pattern?", opts: ["AWS Step Functions", "Amazon EventBridge", "Amazon SQS", "AWS Lambda"], ans: 0, explain: "AWS Step Functions coordinates multiple AWS services into serverless workflows with visual state machines." },
  { domain: 3, task: "3.8", q: "A company wants a managed, centralized place to store application configuration values that workloads can retrieve securely. Which option best matches that configuration-management need?", opts: ["AWS Systems Manager Parameter Store", "Amazon CloudWatch", "AWS Config", "Amazon SQS"], ans: 0, explain: "Systems Manager Parameter Store provides centralized storage for configuration data and parameters." },
  { domain: 3, task: "3.8", q: "A team wants metrics, logs, and alarms in one place so they can watch resource health and react quickly when thresholds are crossed. Which option best addresses that monitoring requirement?", opts: ["AWS X-Ray", "Amazon CloudWatch", "AWS CloudTrail", "AWS Config"], ans: 1, explain: "Amazon CloudWatch monitors AWS resources and applications, collecting metrics, logs, and providing alarms." },
  { domain: 3, task: "3.8", q: "A company wants to patch fleets of EC2 instances and automate repeatable maintenance tasks from a central service. Which option best matches that operations requirement?", opts: ["Amazon CloudWatch", "AWS Systems Manager", "Amazon Inspector", "AWS Config"], ans: 1, explain: "AWS Systems Manager includes capabilities for operational maintenance tasks such as patching and automation." },
  { domain: 3, task: "3.8", q: "A company wants to automate application releases and track operational health. Which combination of services should they use? (Choose TWO)", opts: ["AWS Elastic Beanstalk", "Amazon Connect", "Amazon CloudWatch", "Amazon WorkSpaces", "Amazon SES"], ans: [0, 2], multi: true, explain: "Elastic Beanstalk manages application environments, and CloudWatch tracks health and metrics during releases." },
  { domain: 3, task: "3.8", q: "A company wants operators to run approved administrative actions on EC2 instances without using direct SSH access. Which AWS service supports this requirement?", opts: ["AWS Systems Manager", "Amazon CloudWatch", "AWS Config", "Amazon Route 53"], ans: 0, explain: "AWS Systems Manager helps teams run administrative actions and automation on EC2 instances without relying on direct SSH access." },
  { domain: 3, task: "3.8", q: "A company needs to send push notifications to millions of mobile devices. Which option best supports that messaging pattern?", opts: ["Amazon SES", "Amazon SNS", "Amazon SQS", "Amazon Connect"], ans: 1, explain: "Amazon SNS supports mobile push notifications to millions of devices across platforms like iOS, Android, and Fire OS." },
  { domain: 3, task: "3.8", q: "A company wants to monitor CPU utilization and set an alarm when it exceeds 80%. Which option best addresses that monitoring requirement?", opts: ["AWS X-Ray", "Amazon CloudWatch", "AWS CloudTrail", "AWS Config"], ans: 1, explain: "CloudWatch monitors metrics like CPU utilization and can trigger alarms when thresholds are exceeded." },
  { domain: 3, task: "3.8", q: "A team wants a shared operations view that displays key AWS metrics and alarm status in one place. Which CloudWatch feature should it use?", opts: ["CloudWatch dashboards", "CloudWatch Logs", "CloudWatch Events", "CloudWatch agent"], ans: 0, explain: "CloudWatch dashboards provide customizable views of metrics and alarms for monitoring the health of AWS resources." },
  { domain: 3, task: "3.8", q: "A company needs to stream desktop applications to contractors without providing full virtual desktops. Which service is best?", opts: ["Amazon WorkSpaces", "Amazon AppStream 2.0", "Amazon EC2", "Amazon Lightsail"], ans: 1, explain: "AppStream 2.0 streams individual applications (not full desktops) to users through a web browser." },
  { domain: 3, task: "3.8", q: "A company wants to coordinate several AWS tasks in order and define what should happen if one step fails and needs another attempt. Which Step Functions capability supports this?", opts: ["Error handling with retry and catch", "Dead letter queue", "Message deduplication", "Event replay"], ans: 0, explain: "Step Functions supports built-in error handling with Retry (automatic retries) and Catch (fallback states) for workflow steps." },
  { domain: 3, task: "3.8", q: "A company needs to execute the same approved command across hundreds of EC2 instances without opening SSH access. Which AWS capability should it use?", opts: ["Amazon CloudWatch", "Systems Manager Run Command", "AWS CloudFormation", "AWS Lambda"], ans: 1, explain: "Systems Manager Run Command can execute commands on multiple instances simultaneously without SSH access." },
  { domain: 3, task: "3.1", q: "A company wants infrastructure definitions that can be reviewed in code and reused across environments. Which AWS approaches support that goal? (Select TWO)", opts: ["AWS CloudFormation templates", "Version control for infrastructure definitions", "Manual resource creation in the console", "AWS Trusted Advisor recommendations", "Amazon Inspector scans"], ans: [0, 1], multi: true, explain: "AWS CloudFormation templates and version control help teams review, track, and reuse infrastructure definitions across environments." },
  { domain: 3, task: "3.3", q: "A company is containerizing its microservices and evaluating orchestration options. Which of the following are container orchestration or compute services for running containers on AWS? (Select THREE)", opts: ["Amazon ECS", "Amazon EKS", "AWS Fargate", "AWS Lambda", "Amazon Lightsail"], ans: [0, 1, 2], multi: true, explain: "ECS is AWS-native container orchestration, EKS provides managed Kubernetes, and Fargate is a serverless compute engine for containers used with ECS or EKS. Lambda is serverless compute for functions (not containers in the orchestration sense), and Lightsail is a simplified virtual server service." },
  { domain: 3, task: "3.4", q: "A company is building a new application and needs to choose appropriate database services. Which of the following are fully managed NoSQL database services on AWS? (Select TWO)", opts: ["Amazon DynamoDB", "Amazon DocumentDB", "Amazon Aurora", "Amazon Redshift", "Amazon RDS for MySQL"], ans: [0, 1], multi: true, explain: "DynamoDB is a managed NoSQL key-value and document database, and DocumentDB is a managed MongoDB-compatible document database. Aurora and RDS for MySQL are relational databases, and Redshift is a data warehouse." },
  { domain: 3, task: "3.4", q: "A company needs to improve the read performance of their Amazon Aurora database and also ensure automatic failover if the primary instance fails. Which TWO features should they configure? (Select TWO)", opts: ["Aurora Read Replicas to offload read traffic", "Multi-AZ deployment for automatic failover", "DynamoDB Accelerator (DAX) for caching", "Aurora Serverless v2 for write scaling", "S3 Cross-Region Replication for backups"], ans: [0, 1], multi: true, explain: "Aurora Read Replicas distribute read traffic across multiple instances to improve performance, and Multi-AZ deployment maintains a standby for automatic failover. DAX is specific to DynamoDB, Aurora Serverless addresses scaling differently, and S3 CRR is for object storage replication." },
  { domain: 3, task: "3.5", q: "A company needs to establish private connectivity between their VPC and AWS services like S3 and DynamoDB without traversing the public internet. Which TWO types of VPC endpoints can they use? (Select TWO)", opts: ["Gateway endpoints", "Interface endpoints (AWS PrivateLink)", "Internet Gateway", "NAT Gateway", "Virtual Private Gateway"], ans: [0, 1], multi: true, explain: "Gateway endpoints provide private access to S3 and DynamoDB via route table entries. Interface endpoints use AWS PrivateLink to create ENIs in your subnet for private connectivity to many AWS services. Internet and NAT Gateways route traffic to the internet, and Virtual Private Gateway is for VPN connections." },
  { domain: 3, task: "3.6", q: "A company wants to implement a cost-effective storage strategy for different data access patterns. Which TWO S3 features help automatically optimize storage costs over time? (Select TWO)", opts: ["S3 Intelligent-Tiering", "S3 Lifecycle Policies", "S3 Versioning", "S3 Transfer Acceleration", "S3 Object Lock"], ans: [0, 1], multi: true, explain: "Intelligent-Tiering automatically moves objects between access tiers based on usage patterns, and Lifecycle Policies transition objects to cheaper storage classes or delete them on a defined schedule. Versioning retains object versions, Transfer Acceleration speeds uploads, and Object Lock prevents deletion." },
  { domain: 3, task: "3.6", q: "A company needs shared file storage accessible from multiple EC2 instances. Which TWO AWS services provide managed file system storage? (Select TWO)", opts: ["Amazon EFS", "Amazon FSx for Windows File Server", "Amazon EBS", "Amazon S3", "AWS Storage Gateway"], ans: [0, 1], multi: true, explain: "EFS provides managed NFS file storage mountable by multiple Linux instances, and FSx for Windows File Server provides managed SMB file storage for Windows workloads. EBS is block storage attached to a single instance, S3 is object storage, and Storage Gateway is a hybrid storage service." },
  { domain: 3, task: "3.3", q: "A team needs compute for a short-running job that may run for several minutes without managing servers. Which option best addresses this requirement?", opts: ["Amazon EC2", "AWS Lambda", "Amazon ECS", "AWS Batch"], ans: 1, explain: "AWS Lambda is a serverless compute service that runs code in response to events and fits short-running jobs without server management." },
  { domain: 3, task: "3.1", q: "A company wants to define its AWS infrastructure - VPCs, EC2 instances, and RDS databases - in version-controlled template files so deployments are repeatable. Which option best addresses this requirement?", opts: ["AWS Systems Manager", "AWS CloudFormation", "AWS Service Catalog", "AWS Elastic Beanstalk"], ans: 1, explain: "CloudFormation lets you define infrastructure in JSON or YAML templates that are version-controlled and repeatable. Systems Manager manages existing resources but does not define infrastructure as code. Service Catalog publishes approved products. Elastic Beanstalk is for managed application deployment." },
  { domain: 3, task: "3.2", q: "A company needs to design for high availability within an AWS Region. Which statement about Availability Zones is correct?", opts: ["AZs are isolated locations within a Region with independent power and networking", "AZs are in different countries, providing geographic diversity", "AZs are only logical partitions with no physical separation", "AZs are the same as Regions"], ans: 0, explain: "AZs are physically separate facilities within a Region and are used to improve availability and fault tolerance. They are not different countries and are not the same as Regions." },
  { domain: 3, task: "3.3", q: "A company wants to run short-lived backend functions triggered by API requests without managing any servers. Which option is the best fit for this compute pattern?", opts: ["Amazon EC2 Auto Scaling", "AWS Lambda", "Amazon ECS with AWS Fargate", "AWS Elastic Beanstalk"], ans: 1, explain: "Lambda runs code in response to events such as API requests with no server management and automatic scaling. EC2 Auto Scaling still requires instance management, Fargate is container-oriented, and Elastic Beanstalk is for managed application environments." },
  { domain: 3, task: "3.3", q: "A company runs a legacy Windows-based application that requires a full operating system and persistent local storage. Which compute service should they use?", opts: ["AWS Lambda", "Amazon ECS", "Amazon EC2", "Amazon Lightsail"], ans: 2, explain: "EC2 provides full VM instances with OS-level access, Windows support, and persistent EBS storage. Lambda doesn't provide a full OS. ECS runs containers, not full OS environments. Lightsail is simplified compute but isn't specifically for legacy apps and has fewer customization options." },
  { domain: 3, task: "3.4", q: "A company needs to run complex SQL queries joining multiple tables for their e-commerce order management system, with full ACID transaction support. Which option is the best fit for this data model?", opts: ["Amazon DynamoDB", "Amazon RDS or Amazon Aurora", "Amazon ElastiCache", "Amazon DocumentDB"], ans: 1, explain: "RDS and Aurora provide fully managed relational databases with SQL, joins, and ACID transactions. DynamoDB is NoSQL without complex joins. ElastiCache is an in-memory cache, not a primary database. DocumentDB stores JSON documents, not relational data with complex joins." },
  { domain: 3, task: "3.5", q: "A company needs to isolate their production and development environments in AWS with separate network address ranges and routing. Which service provides this network isolation?", opts: ["AWS IAM policies", "Amazon VPC", "Amazon Route 53", "AWS Direct Connect"], ans: 1, explain: "VPCs provide isolated virtual networks with their own IP ranges, subnets, and routing tables. IAM restricts API access but not network isolation. Route 53 manages DNS, not network segregation. Direct Connect is for on-premises to AWS connectivity, not environment separation." },
  { domain: 3, task: "3.5", q: "A company runs a web application behind an Application Load Balancer and notices uneven traffic distribution during peak hours. They want requests routed based on URL path — /api/* to backend servers and /images/* to a separate fleet. Which load balancer feature supports this?", opts: ["Network Load Balancer", "Application Load Balancer", "Classic Load Balancer", "Gateway Load Balancer"], ans: 1, explain: "ALB supports path-based routing to direct requests to different target groups based on URL paths. NLB operates at Layer 4 without URL inspection. Classic LB has basic routing without path rules. Gateway LB is for inline network appliances, not application routing." },
  { domain: 3, task: "3.6", q: "A company needs to store 500 TB of log data that is rarely accessed but must be retrievable within 12 hours when needed for compliance audits. Which S3 storage class minimizes cost?", opts: ["S3 Standard", "S3 Glacier Deep Archive", "S3 Intelligent-Tiering", "S3 One Zone-IA"], ans: 1, explain: "Glacier Deep Archive is the lowest-cost S3 class, with retrieval within 12 hours — ideal for rarely accessed compliance data. Standard is for frequent access. Intelligent-Tiering adds monitoring fees and is better for unknown patterns. One Zone-IA sacrifices durability for a modest discount." },
  { domain: 3, task: "3.7", q: "A company receives thousands of customer support emails daily and wants to automatically determine whether each email expresses a positive, negative, or neutral sentiment. Which option best addresses that NLP requirement?", opts: ["Amazon Textract", "Amazon Comprehend", "Amazon Polly", "Amazon Lex"], ans: 1, explain: "Comprehend uses NLP to detect sentiment, entities, and key phrases in text. Textract extracts text from scanned documents. Polly converts text to lifelike speech. Lex builds chatbot interfaces." },
  { domain: 3, task: "3.3", q: "A company wants to run Docker containers in production without managing the underlying EC2 instances or cluster infrastructure. Which compute option should they use?", opts: ["Amazon ECS on EC2 instances they manage", "Amazon ECS with AWS Fargate", "Amazon EC2 with Docker installed manually", "AWS Lambda"], ans: 1, explain: "Fargate runs containers without managing servers or clusters. ECS on EC2 requires managing instances. EC2 with Docker means managing everything. Lambda supports container images but has execution limits." },
  { domain: 3, task: "3.2", q: "A company needs to connect their on-premises data center to their AWS VPC with a consistent, low-latency private connection that doesn't traverse the public internet. Which option best addresses this requirement?", opts: ["AWS Site-to-Site VPN", "AWS Direct Connect", "Amazon CloudFront", "AWS Transit Gateway"], ans: 1, explain: "Direct Connect establishes a dedicated physical connection between on-premises and AWS, bypassing the public internet for consistent latency. VPN goes over the internet with variable latency. CloudFront is a CDN, not a network connection. Transit Gateway connects VPCs to each other, not to on-premises." },
  { domain: 3, task: "3.4", q: "A company needs an in-memory caching layer to reduce the load on their RDS database for frequently repeated read queries. Which service should they deploy?", opts: ["Amazon DynamoDB Accelerator (DAX)", "Amazon ElastiCache", "Amazon Redshift Spectrum", "Amazon RDS Read Replicas"], ans: 1, explain: "ElastiCache provides managed Redis or Memcached for microsecond-latency caching of database query results. DAX is specifically for DynamoDB, not RDS. Redshift Spectrum queries S3 data, not caches RDS queries. Read Replicas help but add latency compared to in-memory caching." },
  { domain: 3, task: "3.1", q: "A company wants to deploy a web application quickly while letting AWS handle servers, load balancing, and scaling in the background. Which option best fits that operating model?", opts: ["Amazon EC2", "AWS Elastic Beanstalk", "Amazon Lightsail", "Amazon ECS"], ans: 1, explain: "Elastic Beanstalk automatically handles capacity provisioning, load balancing, scaling, and monitoring for supported application platforms. EC2 requires manual setup, while Lightsail and ECS are different deployment models." },
  { domain: 3, task: "3.7", q: "A company wants to process and analyze real-time clickstream data from their website to detect trending products within seconds. Which option best matches that streaming pattern?", opts: ["Amazon S3 with event notifications for batch processing", "Amazon Kinesis Data Streams for real-time streaming data ingestion", "Amazon Glacier for long-term data archival", "AWS Glue for ETL batch processing jobs"], ans: 1, explain: "Kinesis Data Streams ingests and processes real-time streaming data with sub-second latency. S3 event notifications are near-real-time but not designed for continuous streaming. Glacier is for cold storage archival. Glue runs batch ETL jobs, not real-time stream processing." },
  { domain: 3, task: "3.2", q: "A company wants to reduce the impact of a single Availability Zone failure. Which design choice is best?", opts: ["Deploy across multiple Availability Zones", "Use a single large EC2 instance", "Disable load balancing", "Store all data in one subnet"], ans: 0, explain: "Deploying across multiple Availability Zones improves availability and reduces the blast radius of an AZ failure." },
  { domain: 3, task: "3.3", q: "A company is modernizing application compute on AWS. One workload is event-driven with unpredictable demand and minimal tolerance for server management, while another is a long-running containerized service that should avoid node management. Which compute services are the best fit? (Select TWO)", opts: ["AWS Lambda for the event-driven workload", "AWS Fargate for the containerized service", "Amazon EC2 Dedicated Hosts for both workloads", "Amazon S3 for container orchestration", "AWS Snowball Edge for day-to-day compute"], ans: [0, 1], multi: true, explain: "Lambda is well suited to event-driven, highly variable workloads, and Fargate provides serverless containers without node management. The other choices do not fit the stated compute patterns." },
  { domain: 3, task: "3.3", q: "A retailer has a product image resizing job that runs only when new images are uploaded to Amazon S3. The team does not want to manage servers for the job. Which compute service should they use?", opts: ["Amazon EC2", "AWS Lambda", "Amazon Lightsail", "AWS Batch"], ans: 1, explain: "AWS Lambda is a good fit for event-driven work such as processing new S3 objects without provisioning or managing servers." },
  { domain: 3, task: "3.3", q: "A company runs a legacy application that needs full operating system access and custom agents installed on the host. Which choice best matches those host-level requirements?", opts: ["AWS Lambda", "Amazon EC2", "AWS Fargate", "Amazon S3"], ans: 1, explain: "Amazon EC2 provides virtual machines with operating system access, which is appropriate for legacy applications that need host-level customization." },
  { domain: 3, task: "3.3", q: "A team runs a containerized service and wants AWS to run containers without requiring the team to manage EC2 worker nodes. Which option should they choose?", opts: ["Amazon ECS with AWS Fargate", "Amazon ECS on self-managed EC2", "Amazon EC2 Auto Scaling", "Amazon Lightsail"], ans: 0, explain: "AWS Fargate runs containers without requiring customers to provision or manage EC2 instances." },
  { domain: 3, task: "3.3", q: "A company has a steady web workload that must run continuously and wants to reduce EC2 compute cost with a commitment. Which choice best matches that usage pattern?", opts: ["Spot Instances", "Reserved Instances", "On-Demand Instances", "Dedicated Hosts"], ans: 1, explain: "Reserved Instances are appropriate for steady EC2 usage where the customer can commit to a term in exchange for lower cost." },
  { domain: 3, task: "3.3", q: "A media company runs video transcoding jobs that can restart if capacity is reclaimed. Which EC2 purchasing option should it consider to reduce costs?", opts: ["Dedicated Hosts", "Spot Instances", "On-Demand Instances", "Reserved Instances"], ans: 1, explain: "Spot Instances are suitable for fault-tolerant, interruptible workloads that can handle interruptions." },
  { domain: 3, task: "3.3", q: "A web application must add and remove EC2 instances based on traffic while distributing requests across healthy instances. Which services should be combined? (Choose TWO)", opts: ["Amazon EC2 Auto Scaling", "Elastic Load Balancing", "AWS CloudTrail", "Amazon S3", "AWS IAM Identity Center"], ans: [0, 1], multi: true, explain: "EC2 Auto Scaling adjusts capacity, and Elastic Load Balancing distributes traffic across healthy targets." },
  { domain: 3, task: "3.3", q: "A small business wants a simple virtual private server with bundled pricing to host a low-traffic website. Which service is the simplest fit?", opts: ["Amazon Lightsail", "Amazon EKS", "AWS Lambda", "Amazon Redshift"], ans: 0, explain: "Amazon Lightsail provides simplified virtual private servers with predictable bundled pricing for small workloads." },
  { domain: 3, task: "3.5", q: "A public website needs to route HTTP requests to different target groups based on URL path, such as /api and /images. Which load balancer should be used?", opts: ["Application Load Balancer", "Network Load Balancer", "Gateway Load Balancer", "Classic Load Balancer"], ans: 0, explain: "Application Load Balancer supports HTTP and HTTPS routing features such as path-based routing." },
  { domain: 3, task: "3.5", q: "A trading application needs very low latency TCP traffic distribution across targets and does not require HTTP path routing. Which choice best matches that traffic pattern?", opts: ["Application Load Balancer", "Network Load Balancer", "Classic Load Balancer", "Amazon CloudFront"], ans: 1, explain: "Network Load Balancer is designed for high-performance Layer 4 TCP and UDP traffic distribution." },
  { domain: 3, task: "3.2", q: "A company wants to deliver static website assets to customers globally with lower latency and reduced load on the origin. Which option best addresses this requirement?", opts: ["Amazon CloudFront", "AWS Direct Connect", "Amazon VPC", "AWS Transit Gateway"], ans: 0, explain: "Amazon CloudFront caches content at edge locations to reduce latency and offload the origin." },
  { domain: 3, task: "3.5", q: "A company needs a private dedicated network connection from its data center to AWS for predictable network performance. Which service should it choose?", opts: ["AWS Site-to-Site VPN", "AWS Direct Connect", "Internet Gateway", "NAT Gateway"], ans: 1, explain: "AWS Direct Connect provides a dedicated private connection between an on-premises environment and AWS." },
  { domain: 3, task: "3.5", q: "A company needs encrypted connectivity from its on-premises network to a VPC quickly, using the public internet. Which choice best matches those connectivity constraints?", opts: ["AWS Direct Connect", "AWS Site-to-Site VPN", "VPC peering", "AWS PrivateLink"], ans: 1, explain: "AWS Site-to-Site VPN creates encrypted tunnels over the public internet between on-premises networks and AWS." },
  { domain: 3, task: "3.5", q: "A workload in a private subnet must download operating system updates from the internet, but inbound internet connections to the instances should not be allowed. Which component should be used?", opts: ["NAT gateway", "Internet gateway attached directly to the instances", "VPC peering", "AWS Direct Connect"], ans: 0, explain: "A NAT gateway enables outbound internet access from private subnets while preventing inbound connections initiated from the internet." },
  { domain: 3, task: "3.5", q: "An application in a VPC needs private access to Amazon S3 without routing traffic over the public internet. Which option should the team use?", opts: ["VPC endpoint", "Internet gateway", "NAT gateway", "AWS Site-to-Site VPN"], ans: 0, explain: "A VPC endpoint provides private connectivity from a VPC to supported AWS services such as Amazon S3." },
  { domain: 3, task: "3.5", q: "A company wants one central hub to connect many VPCs and on-premises networks instead of maintaining many separate peering connections. Which option best addresses this requirement?", opts: ["AWS Transit Gateway", "Amazon Route 53", "AWS Global Accelerator", "Amazon CloudFront"], ans: 0, explain: "AWS Transit Gateway acts as a hub for connecting VPCs and on-premises networks." },
  { domain: 3, task: "3.6", q: "A team needs object storage for millions of images and wants high durability without managing storage servers. Which option best addresses this requirement?", opts: ["Amazon S3", "Amazon EBS", "Amazon EFS", "Instance store"], ans: 0, explain: "Amazon S3 provides highly durable, scalable object storage without server management." },
  { domain: 3, task: "3.6", q: "A database running on one EC2 instance needs low-latency persistent block storage that survives instance stops and starts. Which storage service should be used?", opts: ["Amazon EBS", "Amazon S3", "Amazon EFS", "S3 Glacier Deep Archive"], ans: 0, explain: "Amazon EBS provides persistent block storage volumes for EC2 instances." },
  { domain: 3, task: "3.6", q: "A Linux application running on several EC2 instances in multiple Availability Zones needs a shared file system. Which service should the team choose?", opts: ["Amazon EFS", "Amazon EBS", "Amazon S3", "Instance store"], ans: 0, explain: "Amazon EFS provides a managed file system that can be mounted by multiple Linux instances across Availability Zones." },
  { domain: 3, task: "3.6", q: "A company stores audit logs that are rarely accessed and can wait hours for retrieval. Which S3 storage class should it consider for the lowest long-term storage cost?", opts: ["S3 Standard", "S3 One Zone-IA", "S3 Glacier Deep Archive", "S3 Standard-IA"], ans: 2, explain: "S3 Glacier Deep Archive is designed for long-term archive data that is rarely accessed and can tolerate longer retrieval times." },
  { domain: 3, task: "3.6", q: "A team does not know whether a new S3 data set will be accessed frequently or rarely over time. Which S3 storage class can automatically move objects between access tiers?", opts: ["S3 Standard", "S3 Intelligent-Tiering", "S3 One Zone-IA", "S3 Glacier Deep Archive"], ans: 1, explain: "S3 Intelligent-Tiering automatically moves objects between access tiers based on changing access patterns." },
  { domain: 3, task: "3.6", q: "A company needs to keep on-premises applications while giving them low-latency access to cloud-backed storage. Which AWS service supports this hybrid storage pattern?", opts: ["AWS Storage Gateway", "Amazon CloudFront", "Amazon Route 53", "Amazon EBS"], ans: 0, explain: "AWS Storage Gateway connects on-premises applications to AWS cloud storage through hybrid storage gateways." },
  { domain: 3, task: "3.4", q: "An application needs a managed relational database for SQL queries, backups, patching, and high availability options. Which service family should the team choose?", opts: ["Amazon RDS", "Amazon DynamoDB", "Amazon ElastiCache", "Amazon S3"], ans: 0, explain: "Amazon RDS is the managed relational database service family that supports SQL engines with operational automation." },
  { domain: 3, task: "3.4", q: "A globally used shopping cart service needs a key-value database that can scale with very high request volume. Which option best matches that access pattern?", opts: ["Amazon DynamoDB", "Amazon Redshift", "Amazon RDS", "Amazon Neptune"], ans: 0, explain: "Amazon DynamoDB is a managed NoSQL key-value and document database designed for high-scale workloads." },
  { domain: 3, task: "3.4", q: "A company wants a MySQL- and PostgreSQL-compatible relational database with high performance and managed operations. Which service should it consider?", opts: ["Amazon Aurora", "Amazon DynamoDB", "Amazon ElastiCache", "Amazon Athena"], ans: 0, explain: "Amazon Aurora is a MySQL- and PostgreSQL-compatible managed relational database engine." },
  { domain: 3, task: "3.4", q: "A reporting team needs a managed data warehouse for SQL analytics across large volumes of structured business data. Which option best addresses this requirement?", opts: ["Amazon Redshift", "Amazon RDS", "Amazon ElastiCache", "Amazon Neptune"], ans: 0, explain: "Amazon Redshift is a managed data warehouse service for analytics over large data sets." },
  { domain: 3, task: "3.4", q: "An application repeatedly reads the same product data from a relational database and needs microsecond-latency caching. Which service should be added?", opts: ["Amazon ElastiCache", "Amazon Redshift", "Amazon Athena", "Amazon S3"], ans: 0, explain: "Amazon ElastiCache provides managed in-memory caching for low-latency access to frequently read data." },
  { domain: 3, task: "3.4", q: "A company must preserve a cryptographically verifiable history of financial transactions in an application ledger. Which option best matches that ledger requirement?", opts: ["Amazon QLDB", "Amazon ElastiCache", "Amazon Redshift", "Amazon RDS"], ans: 0, explain: "Amazon QLDB is a managed ledger database with an immutable, cryptographically verifiable transaction log." },
  { domain: 3, task: "3.7", q: "A support team receives thousands of customer emails and wants to identify sentiment and key phrases automatically. Which option best addresses this requirement?", opts: ["Amazon Comprehend", "Amazon Textract", "Amazon Polly", "Amazon Rekognition"], ans: 0, explain: "Amazon Comprehend uses natural language processing to identify sentiment, entities, and key phrases in text." },
  { domain: 3, task: "3.7", q: "An insurance company receives scanned claim forms and wants to extract printed text from them. Which AI service should it use?", opts: ["Amazon Textract", "Amazon Comprehend", "Amazon Translate", "Amazon Polly"], ans: 0, explain: "Amazon Textract extracts printed and handwritten text and data from documents." },
  { domain: 3, task: "3.7", q: "A media library needs to detect objects and labels in uploaded images. Which AWS AI service should it use?", opts: ["Amazon Rekognition", "Amazon Comprehend", "Amazon Polly", "Amazon Lex"], ans: 0, explain: "Amazon Rekognition can analyze images and videos to detect objects, scenes, and labels." },
  { domain: 3, task: "3.7", q: "A training platform needs to convert written lesson content into natural-sounding speech. Which option best addresses this requirement?", opts: ["Amazon Polly", "Amazon Transcribe", "Amazon Translate", "Amazon Lex"], ans: 0, explain: "Amazon Polly converts text into lifelike speech." },
  { domain: 3, task: "3.7", q: "A contact center wants a chatbot that can understand user intent and collect information through conversation. Which option best addresses this requirement?", opts: ["Amazon Lex", "Amazon Polly", "Amazon Textract", "Amazon Rekognition"], ans: 0, explain: "Amazon Lex is used to build conversational interfaces such as chatbots and voice bots." },
  { domain: 3, task: "3.7", q: "A data team needs to run SQL queries directly against files stored in Amazon S3 without managing database servers. Which option best addresses this requirement?", opts: ["Amazon Athena", "Amazon Redshift", "Amazon RDS", "Amazon QuickSight"], ans: 0, explain: "Amazon Athena is a serverless query service that can run SQL against data stored in Amazon S3." },
  { domain: 3, task: "3.7", q: "Executives need interactive dashboards and visualizations based on AWS data sources. Which option is the best fit for this situation?", opts: ["Amazon QuickSight", "Amazon S3", "AWS Glue", "Amazon Kinesis Data Streams"], ans: 0, explain: "Amazon QuickSight is AWS's managed business intelligence service for dashboards and visualizations." },
  { domain: 3, task: "3.7", q: "A website needs to ingest clickstream events continuously and analyze trends within seconds. Which service should be used for real-time streaming data ingestion?", opts: ["Amazon Kinesis Data Streams", "AWS Glue", "Amazon Athena", "S3 Glacier Deep Archive"], ans: 0, explain: "Amazon Kinesis Data Streams is designed for real-time streaming data ingestion and processing." },
  { domain: 3, task: "3.8", q: "A company needs to decouple a web application from a background image-processing worker so requests can be buffered during spikes. Which option best addresses this requirement?", opts: ["Amazon SQS", "Amazon Route 53", "AWS CloudTrail", "Amazon CloudFront"], ans: 0, explain: "Amazon SQS provides message queues that decouple application components and buffer work between producers and consumers." },
  { domain: 3, task: "3.8", q: "An operations team needs to notify multiple subscribers when a production alarm is triggered. Which service should it use for pub/sub notifications?", opts: ["Amazon SNS", "Amazon SQS", "AWS Step Functions", "Amazon Athena"], ans: 0, explain: "Amazon SNS is a pub/sub messaging service that can fan out notifications to multiple subscribers." },
  { domain: 3, task: "3.8", q: "A workflow must coordinate several steps, including invoking Lambda functions and waiting for approvals. Which service should orchestrate the workflow?", opts: ["AWS Step Functions", "Amazon SQS", "Amazon CloudFront", "AWS Config"], ans: 0, explain: "AWS Step Functions coordinates multi-step workflows across AWS services." },
  { domain: 3, task: "3.8", q: "A team wants to react when objects are uploaded to S3 and route those events to downstream AWS services. Which service is the best fit for event routing?", opts: ["Amazon EventBridge", "Amazon Redshift", "AWS Direct Connect", "Amazon EFS"], ans: 0, explain: "Amazon EventBridge routes events from AWS services and applications to targets for event-driven architectures." },
  { domain: 3, task: "3.8", q: "A company wants to monitor EC2 CPU utilization, application logs, and alarms from one AWS monitoring service. Which option best addresses this requirement?", opts: ["Amazon CloudWatch", "AWS CloudTrail", "AWS Config", "AWS Organizations"], ans: 0, explain: "Amazon CloudWatch collects metrics and logs and supports alarms for AWS resources and applications." },
  { domain: 3, task: "3.8", q: "A security team needs a record of API calls made in an AWS account for auditing. Which service provides this event history?", opts: ["AWS CloudTrail", "Amazon CloudWatch", "Amazon GuardDuty", "AWS Trusted Advisor"], ans: 0, explain: "AWS CloudTrail records AWS API activity and account events for auditing and governance." },
  { domain: 3, task: "3.1", q: "A team wants to deploy the same reviewed infrastructure configuration for development, test, and production accounts. Which choice best supports that consistency goal?", opts: ["CloudFormation templates", "Manual console screenshots", "CloudWatch alarms", "Route 53 health checks"], ans: 0, explain: "CloudFormation templates let teams define infrastructure once and deploy it consistently across environments." },
  { domain: 3, task: "3.1", q: "A development team wants AWS to provision the environment for a web application from uploaded application code while still allowing the team to retain control of the underlying resources if needed. Which service should it choose?", opts: ["AWS Elastic Beanstalk", "Amazon QuickSight", "Amazon Route 53", "AWS CloudTrail"], ans: 0, explain: "AWS Elastic Beanstalk provisions and manages application environments while still allowing access to the underlying AWS resources." }
];
